import { AccountCategory } from '@domain/accountCategory';

type DocumentStatus = 'unreviewed' | 'verified' | 'rejected' | 'deleted';

export type DocumentFile = {
  name: string;
  size: number;
  url: string;
};

export type AccountDocument = {
  documentType: AccountDocumentType;
  file: DocumentFile;
  id: string;
  status: DocumentStatus;
};

export type UpdateAccountDocument = {
  accountId: string;
  documentName: string;
  documentType: AccountDocumentType;
  file: string;
};

type DocumentCategoryDefinition<Documents extends readonly string[]> = {
  documents: Documents;
};

type ConditionalRequirement<Category extends string> =
  | {
      predicate: { accountCategory: AccountCategory; state: string };
      categories: readonly Category[];
    }
  | {
      predicate: { accountCategory: AccountCategory; subCategory: string };
      categories: readonly Category[];
    };

type FlattenDocuments<Categories extends Record<string, DocumentCategoryDefinition<readonly string[]>>> =
  Categories[keyof Categories]['documents'][number];

type AccountCategoriesToDocumentCategories<
  Categories extends Record<string, DocumentCategoryDefinition<readonly string[]>>
> = Record<AccountCategory, readonly (keyof Categories)[]>;

const DOCUMENT_DOMAIN = defineDocumentDomain({
  categories: {
    ein: { documents: ['irs_cp_575'] as const },
    ownership_affiliation: {
      documents: ['meeting_minutes', 'articles_of_incorporation', 'annual_report', 'vendor_contract'] as const,
    },
    state_incorporation: {
      documents: ['articles_of_incorporation', 'annual_report', 'state_registration_paperwork'] as const,
    },
    nonprofit_determination_letter: { documents: ['irs_501c'] as const },
    candidate_or_pac_filing: {
      documents: [
        'appointment_of_treasurer',
        'statement_of_organization',
        'campaign_finance_report',
        'committee_registration',
      ] as const,
    },
    california_charity_registration: { documents: ['state_charity_registration'] as const },
    section_527_pac_designation: { documents: ['irs_8871'] as const },
  },
  baseRequirements: {
    'church-ministry': ['ein', 'ownership_affiliation', 'state_incorporation'],
    education: ['ein', 'ownership_affiliation'],
    nonprofit: ['ein', 'ownership_affiliation', 'state_incorporation', 'nonprofit_determination_letter'],
    political: ['ein', 'ownership_affiliation', 'candidate_or_pac_filing'],
    vendor: ['ein', 'ownership_affiliation', 'state_incorporation'],
  },
  conditionalRequirements: [
    {
      predicate: { accountCategory: 'nonprofit', state: 'CA' },
      categories: ['california_charity_registration'],
    },
    {
      predicate: { accountCategory: 'political', subCategory: 'section_527_pac' },
      categories: ['section_527_pac_designation'],
    },
  ],
});

type DocumentDomain = typeof DOCUMENT_DOMAIN;
export type DocumentCategory = keyof DocumentDomain['categories'];
export type AccountDocumentType = FlattenDocuments<DocumentDomain['categories']>;
export type AccountDocumentCategories = Record<DocumentCategory, AccountDocumentType[]>;

const DOCUMENT_CATEGORY_SET = new Set<DocumentCategory>(
  Object.keys(DOCUMENT_DOMAIN.categories) as DocumentCategory[]
);

export function getRequiredDocumentCategories({
  accountCategory,
  subCategory,
  state,
}: {
  accountCategory: AccountCategory | null;
  subCategory?: string | null;
  state?: string | null;
}): Partial<Record<DocumentCategory, AccountDocumentType[]>> {
  if (!accountCategory) {
    return {};
  }

  // TODO: we should look this up from the server side endpoint so that there is one source of truth
  //  but we can keep this as a fallback for now. Note that required documents
  //  are not only tied to account category, they can be based on state like the 'california_charity_registration'
  //  or sub-category like 'section_527_pac_designation'
  const categories: DocumentCategory[] = [
    ...DOCUMENT_DOMAIN.baseRequirements[accountCategory],
    ...collectConditionalCategories({
      accountCategory,
      state,
      subCategory,
    }),
  ];

  const requiredDocCategories: Partial<Record<DocumentCategory, AccountDocumentType[]>> = {};

  for (const category of new Set(categories)) {
    requiredDocCategories[category] = [...DOCUMENT_DOMAIN.categories[category].documents];
  }

  return requiredDocCategories;
}

export function getRequiredDocumentCategoriesByRequiredDocuments(
  requiredCategories: string[]
): Partial<Record<DocumentCategory, AccountDocumentType[]>> {
  const requiredDocCategories: Partial<Record<DocumentCategory, AccountDocumentType[]>> = {};
  for (const requiredCategory of requiredCategories) {
    if (isDocumentCategory(requiredCategory)) {
      requiredDocCategories[requiredCategory] = [...DOCUMENT_DOMAIN.categories[requiredCategory].documents];
    } else {
      console.error(`Document category ${requiredCategory} not found`);
    }
  }
  return requiredDocCategories;
}

export function getDocumentsByCategory(category: AccountCategory | null) {
  if (!category) {
    return [];
  }
  const docsByCategory = DOCUMENT_DOMAIN.baseRequirements[category].flatMap(
    (documentCategory) => DOCUMENT_DOMAIN.categories[documentCategory].documents
  );
  // dedupe
  return [...new Set(docsByCategory)];
}

function defineDocumentDomain<
  Categories extends Record<string, DocumentCategoryDefinition<readonly string[]>>,
  BaseRequirements extends AccountCategoriesToDocumentCategories<Categories>,
  ConditionalRequirements extends readonly ConditionalRequirement<keyof Categories>[]
>(domain: {
  categories: Categories;
  baseRequirements: BaseRequirements;
  conditionalRequirements?: ConditionalRequirements;
}) {
  return domain;
}

function collectConditionalCategories({
  accountCategory,
  state,
  subCategory,
}: {
  accountCategory: AccountCategory;
  state?: string | null;
  subCategory?: string | null;
}): DocumentCategory[] {
  if (!DOCUMENT_DOMAIN.conditionalRequirements) {
    return [];
  }

  const normalizedState = state?.toUpperCase();

  return DOCUMENT_DOMAIN.conditionalRequirements.flatMap(({ predicate, categories }) => {
    if (predicate.accountCategory !== accountCategory) {
      return [];
    }

    if ('state' in predicate && predicate.state === normalizedState) {
      return categories;
    }

    if ('subCategory' in predicate && predicate.subCategory === subCategory) {
      return categories;
    }

    return [];
  }) as DocumentCategory[];
}

function isDocumentCategory(value: string): value is DocumentCategory {
  return DOCUMENT_CATEGORY_SET.has(value as DocumentCategory);
}

