export function getRequiredDocumentCategoriesByRequiredDocuments(
  requiredCategories: string[]
): Partial<Record<DocumentCategory, AccountDocumentType[]>> {
  const requiredDocCategories: Partial<Record<DocumentCategory, AccountDocumentType[]>> = {};
  for (const requiredCategory of requiredCategories) {
    if (isDocumentCategory(requiredCategory)) {
      requiredDocCategories[requiredCategory] = [
        ...DOCUMENT_DOMAIN.categories[requiredCategory].documents,
      ];
    } else {
      console.error(`Document category ${requiredCategory} not found`);
    }
  }
  return requiredDocCategories;
}

export function getDocumentsByCategory(category: AccountCategory | null) {
  if (!category) {
    return [];
  }
  const docsByCategory = DOCUMENT_DOMAIN.baseRequirements[category].flatMap(
    (documentCategory) => DOCUMENT_DOMAIN.categories[documentCategory].documents
  );
  // dedupe
  return [...new Set(docsByCategory)];
}

function defineDocumentDomain<
  Categories extends Record<string, DocumentCategoryDefinition<readonly string[]>>,
  BaseRequirements extends AccountCategoriesToDocumentCategories<Categories>,
  ConditionalRequirements extends readonly ConditionalRequirement<keyof Categories>[],
  Uncategorized extends readonly string[] | undefined,
>(domain: {
  categories: Categories;
  uncategorizedDocuments?: Uncategorized;
  baseRequirements: BaseRequirements;
  conditionalRequirements?: ConditionalRequirements;
}) {
  return domain;
}

function collectConditionalCategories({
  accountCategory,
  state,
  subCategory,
}: {
  accountCategory: AccountCategory;
  state?: string | null;
  subCategory?: string | null;
}): DocumentCategory[] {
  if (!DOCUMENT_DOMAIN.conditionalRequirements) {
    return [];
  }

  const normalizedState = state?.toUpperCase();

  return DOCUMENT_DOMAIN.conditionalRequirements.flatMap(({ predicate, categories }) => {
    if (predicate.accountCategory !== accountCategory) {
      return [];
    }

    if ('state' in predicate && predicate.state === normalizedState) {
      return categories;
    }

    if ('subCategory' in predicate && predicate.subCategory === subCategory) {
      return categories;
    }

    return [];
  }) as DocumentCategory[];
}

function isDocumentCategory(value: string): value is DocumentCategory {
  return DOCUMENT_CATEGORY_SET.has(value as DocumentCategory);
}
